#include <bits/stdc++.h>
using namespace std;
const int N=550;
int n,m,a[N][N][2];
long long s[N][N][2],f[N][N];
int main(){
	while(1){
		scanf("%d%d",&n,&m);
		if(!n && !m)
			break;
		memset(f,0,sizeof(f));
		memset(s,0,sizeof(s));
		for(int t=0;t<2;t++)
			for(int i=1;i<=n;i++)
				for(int j=1;j<=m;j++)
					scanf("%d",&a[i][j][t]);
		for(int i=1;i<=n;i++)
			for(int j=1;j<=m;j++)
				s[i][j][0]=s[i][j-1][0]+a[i][j][0],s[i][j][1]=s[i-1][j][1]+a[i][j][1];
		for(int i=1;i<=n;i++)
			for(int j=1;j<=m;j++)
				f[i][j]=max(f[i-1][j]+s[i][j][0],f[i][j-1]+s[i][j][1]);
		printf("%lld\n",f[n][m]);
	}
	return 0;
}
